// Token del bot
const BOT_TOKEN = '8524499239:AAEgU7QiBZMwJ1YPErkHVGJ23CT5IzWUMGw';

// Obtener el último update_id guardado
const lastUpdateId = $workflow.staticData.lastUpdateId || 0;

// Hacer request a Telegram API
const response = await fetch(`https://api.telegram.org/bot${BOT_TOKEN}/getUpdates`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    offset: lastUpdateId + 1,
    timeout: 5,
    allowed_updates: ['message']
  })
});

const data = await response.json();

if (!data.ok || !data.result || data.result.length === 0) {
  return [];
}

// Guardar el último update_id
const lastUpdate = data.result[data.result.length - 1];
$workflow.staticData.lastUpdateId = lastUpdate.update_id;

// Retornar solo mensajes de texto
return data.result
  .filter(update => update.message && update.message.text)
  .map(update => ({
    json: {
      update_id: update.update_id,
      message_id: update.message.message_id,
      chat_id: update.message.chat.id,
      text: update.message.text,
      from: update.message.from,
      bot_token: BOT_TOKEN
    }
  }));

const chatId = $input.item.json.chat_id;
const botToken = $input.item.json.bot_token;

try {
  // Llamar al backend
  const healthResponse = await fetch('http://host.docker.internal:3000/health', {
    method: 'GET',
    headers: { 'Content-Type': 'application/json' }
  });

  const health = await healthResponse.json();

  const uptimeMinutes = Math.floor((health.uptime || 0) / 60);
  const uptimeSeconds = Math.floor((health.uptime || 0) % 60);

  const message = `📊 *Estado del Sistema UIDE*\n\n` +
                  `✅ Backend: ${health.status === 'OK' ? 'Operativo ✓' : 'Error ✗'}\n` +
                  `🕐 Timestamp: ${new Date(health.timestamp).toLocaleString('es-EC')}\n` +
                  `⏱️ Uptime: ${uptimeMinutes}m ${uptimeSeconds}s\n\n` +
                  `Sistema funcionando correctamente.`;

  // Enviar respuesta a Telegram
  await fetch(`https://api.telegram.org/bot${botToken}/sendMessage`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      chat_id: chatId,
      text: message,
      parse_mode: 'Markdown'
    })
  });

  return [{ json: { success: true, message: 'Estado enviado' } }];

} catch (error) {
  // Si falla el backend, enviar mensaje de error
  const errorMessage = `❌ *Error del Sistema*\n\n` +
                       `No se pudo conectar con el backend.\n` +
                       `Error: ${error.message}`;

  await fetch(`https://api.telegram.org/bot${botToken}/sendMessage`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      chat_id: chatId,
      text: errorMessage,
      parse_mode: 'Markdown'
    })
  });

  return [{ json: { success: false, error: error.message } }];
}

const chatId = $input.item.json.chat_id;
const text = $input.item.json.text;
const botToken = $input.item.json.bot_token;

let responseText = '';

if (text.startsWith('/start') || text.startsWith('/help')) {
  responseText = `🤖 *Bot de Gestión de Aulas UIDE*\n\n` +
                 `¡Bienvenido! Este bot te ayuda a gestionar las aulas.\n\n` +
                 `*Comandos disponibles:*\n` +
                 `/estado - Ver estado del sistema\n` +
                 `/help - Mostrar esta ayuda\n\n` +
                 `_Modo: Polling Local_`;
} else {
  responseText = `ℹ️ Comando no reconocido: \`${text}\`\n\n` +
                 `Usa /help para ver los comandos disponibles.`;
}

// Enviar respuesta
await fetch(`https://api.telegram.org/bot${botToken}/sendMessage`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    chat_id: chatId,
    text: responseText,
    parse_mode: 'Markdown'
  })
});

return [{ json: { success: true, command: text } }];
